Функция ПолучитьДолгПоКонтрагенту(Контрагент) Экспорт

    Запрос = Новый Запрос;
    Запрос.Текст =
        "ВЫБРАТЬ
        |    Вр.Сумма КАК СуммаДолга
        |ИЗ
        |    РегистрНакопления.Взаиморасчеты КАК Вр
        |ГДЕ
        |    Вр.Договор В
        |        (ВЫБРАТЬ
        |            Д.Ссылка
        |        ИЗ
        |            Справочник.Договоры КАК Д
        |        ГДЕ
        |            Д.Владелец = &Контрагент)
        |    И Вр.Сумма > 0";

    Запрос.УстановитьПараметр("Контрагент", Контрагент);

    Результат = Запрос.Выполнить();
    Выборка = Результат.Выбрать();

    Если Выборка.Следующий() Тогда
        Возврат Выборка.СуммаДолга;
    Иначе
        Возврат 0;
    КонецЕсли;

КонецФункции
